window.TAROT_CARD_MEANINGS = Object.fromEntries([
['major-00-fool',{long:`Шут у Уэйта открывает путешествие через все старшие арканы. На карте человек стоит у края обрыва с легкой котомкой, белой розой и собакой рядом: это образ свободы, невинности, первого шага и тонкого предупреждения об опасности. Для новичка важно не сводить Шута к глупости. Чаще это состояние до опыта, когда старые правила еще не сковали движение, а вся дорога только начинается.`,love:`Легкое начало, флирт, свежий интерес, связь без тяжелой формы.`,work:`Эксперимент, новая роль, пробный проект, обучение через действие.`,advice:`Иди вперед, но смотри под ноги.`,rev:`беспечность, незрелый риск, бегство от ответственности или шаг без проверки реальности.`}],
['major-01-magician',{long:`Маг стоит у стола с символами четырех мастей: жезлом, кубком, мечом и пентаклем. У него уже есть инструменты, воля, речь и способность соединить идею с действием. Уэйт подчеркивает тему мастерства и проводника силы: импульс сверху должен быть проведен в земную форму. Новичку стоит смотреть, где в ситуации человек может не ждать разрешения, а сам сделать точный ход.`,love:`Активное проявление, харизма, флирт, инициатива.`,work:`Переговоры, презентация, запуск, профессиональный навык.`,advice:`Собери инструменты и действуй конкретно.`,rev:`манипуляция, пустые обещания, злоупотребление влиянием или неумение применить инструменты.`}],
['major-02-high-priestess',{long:`Жрица сидит между колоннами у завесы и держит знание, которое нельзя получить грубым нажимом. Это карта тайны, внутреннего знания, памяти, наблюдения и паузы перед ответом. По Уэйту она связана с тем, что скрыто за видимым слоем, и требует не торопиться с выводами. В раскладе Жрица часто говорит: не все сказано, не все известно, но знаки уже есть.`,love:`Недосказанность, тайное чувство, дистанция, скрытый мотив.`,work:`Аналитика, закрытая информация, исследование, ожидание данных.`,advice:`Слушай тишину и не выдавливай ответ силой.`,rev:`подавленная интуиция, секретность, холодная дистанция или отказ видеть скрытые факты.`}],
['major-03-empress',{long:`Императрица окружена природой, зерном, водой и символами Венеры. Это не просто карта женщины или матери, а образ живой силы, которая выращивает, питает и создает условия для созревания. Уэйт связывает ее с плодородием, изобилием, красотой и естественным ростом. Новичку полезно смотреть, где ситуация нуждается не в рывке, а в тепле, ресурсе, телесности и хорошем уходе.`,love:`Тепло, нежность, притяжение, забота и телесная близость.`,work:`Плодородный проект, творческий продукт, рост дохода, хорошая среда.`,advice:`Питай то, что хочешь вырастить, но не душишь рост опекой.`,rev:`избыточная опека, лень, зависимость от комфорта или истощение творческого ресурса.`}],
['major-04-emperor',{long:`Император сидит на троне и показывает закон формы: границы, власть, порядок и ответственность. Если Императрица выращивает живое, Император строит рамку, в которой живое не распадается. Уэйт дает ему смысл устойчивой силы, управления и способности удерживать территорию. Для новичка карта часто отвечает на вопрос: где нужна структура, решение, официальный статус или зрелая позиция.`,love:`Серьезность, статус, границы, вопрос власти и ответственности.`,work:`Начальник, регламент, стратегия, договор, управление.`,advice:`Поставь границу так, чтобы она защищала, а не превращалась в стену.`,rev:`жесткий контроль, упрямство, слабые границы или страх потерять власть.`}],
['major-05-hierophant',{long:`Иерофант связан с традицией, обучением, посвящением и системой правил. Он передает знание не как личную догадку, а как часть школы, института, веры или морального порядка. Уэйт видит в нем духовного наставника и хранителя признанной формы. В раскладе карта спрашивает: действует ли человек в согласии с ценностями, законом, сообществом или авторитетом.`,love:`Официальный союз, семейные правила, моральный выбор, общие ценности.`,work:`Обучение, сертификация, наставник, корпоративная система.`,advice:`Следуй правилу, если в нем есть смысл, а не только страх быть неправильным.`,rev:`догматизм, давление традиции, бунт без смысла или зависимость от чужого авторитета.`}],
['major-06-lovers',{long:`Влюбленные у Уэйта говорят не только о романтике, но и о выборе по ценностям. На карте важны открытость, союз и благословение, но глубинный смысл карты в развилке: человек выбирает связь, путь, желание или честность перед собой. Для новичка это карта притяжения, но также вопроса о согласии внутреннего и внешнего выбора. В тени она дает сомнения, треугольники и раздвоенность.`,love:`Взаимный выбор, сильная химия, проверка ценностей.`,work:`Партнерство, развилка, решение между выгодой и правильностью.`,advice:`Выбирай то, с чем готов жить дальше.`,rev:`сомнение, раздвоенность, зависимость от одобрения или выбор не по себе.`}],
['major-07-chariot',{long:`Колесница показывает движение, волю и победу через управление разнонаправленными силами. Возничий не просто едет вперед: он держит курс и собирает противоречивые импульсы в одно направление. Уэйт подчеркивает триумф, контроль и продвижение. В раскладе карта часто говорит о поездке, дедлайне, конкуренции, рывке или необходимости взять управление в свои руки.`,love:`Активное продвижение, завоевание, сильная динамика, риск давления.`,work:`Запуск, командировка, дедлайн, соревнование, управление проектом.`,advice:`Проверь курс до того, как нажимать на скорость.`,rev:`потеря управления, спешка, конфликт направлений или движение ради движения.`}],
['major-08-strength',{long:`Сила у Уэйта показывает женщину и льва: инстинкт приручается не насилием, а спокойствием, доверием и внутренним достоинством. Это карта выдержки, смелости, телесной уверенности и влияния без грубого давления. Новичку важно отличать ее от Императора: здесь власть мягкая, внутренняя, живая. Карта говорит, что сильное чувство можно не подавлять, а приручить.`,love:`Притяжение, терпение, работа с сильными чувствами без разрушения.`,work:`Выдержка, переговоры, личный авторитет, спокойное лидерство.`,advice:`Не ломай зверя, научись говорить с ним.`,rev:`усталость от самоконтроля, подавленная страсть, слабая воля или грубая сила вместо внутренней.`}],
['major-09-hermit',{long:`Отшельник с фонарем показывает внутренний поиск, зрелую паузу и знание, которое открывается в одиночестве. Это не обязательно изоляция как проблема: иногда нужно выйти из шума, чтобы увидеть следующий точный шаг. Уэйт связывает карту с благоразумием, поиском и скрытым светом опыта. В раскладе она говорит об экспертизе, самоанализе, наставничестве или необходимости дистанции.`,love:`Пауза, личное пространство, честный разговор с собой.`,work:`Исследование, экспертиза, самостоятельная задача, преподавание.`,advice:`Убери шум и посмотри, какой ответ остается в тишине.`,rev:`изоляция, холодность, застревание в анализе или отказ делиться светом опыта.`}],
['major-10-wheel-of-fortune',{long:`Колесо Фортуны показывает циклы, смену обстоятельств и ту часть жизни, которую нельзя полностью контролировать. В традиции Уэйта это карта поворота судьбы, времени, повторяющихся сценариев и неожиданной возможности. Новичку полезно читать ее не как простую удачу, а как движение цикла: что поднимается, что уходит вниз, какой урок повторяется. Карта учит ловить момент.`,love:`Смена динамики, возвращение темы, неожиданный шанс.`,work:`Изменение условий, новый этап проекта, удачный момент, внешний фактор.`,advice:`Не спорь с поворотом, ищи точку входа в новый цикл.`,rev:`повтор старого сценария, сопротивление переменам или ощущение, что события крутят человеком.`}],
['major-11-justice',{long:`Справедливость держит весы и меч: нужно взвесить факты и назвать решение. По Уэйту карта связана с законом, равновесием, правдой и последствиями поступков. Она не утешает, но делает ситуацию прозрачной: что сделано, то имеет цену. В раскладе карта часто говорит о документах, договоре, честном разговоре, ответственности и необходимости убрать самообман.`,love:`Равный обмен, честность, договоренности, признание вклада.`,work:`Контракт, проверка, отчетность, юридическая тема, решение по правилам.`,advice:`Смотри не на то, как хочется, а на то, что честно.`,rev:`несправедливость, перекос обмена, формальная правота без честности или уход от ответственности.`}],
['major-12-hanged-man',{long:`Повешенный показывает остановку и переворот перспективы. Уэйт связывает эту карту с жертвой, ожиданием, необычным взглядом и внутренним просветлением через отказ от прежнего способа действия. Это не всегда поражение: иногда ситуация требует перестать дергать дверь, которая открывается в другую сторону. Новичку стоит искать, где нужна пауза, переоценка и отпускание контроля.`,love:`Зависшая ситуация, пауза, необходимость увидеть позицию другого.`,work:`Задержка, пересмотр стратегии, ожидание решения, задача не решается лобовой атакой.`,advice:`Меняй взгляд, а не просто усиливай давление.`,rev:`бессмысленное зависание, роль жертвы, сопротивление новому взгляду или пауза без осознания.`}],
['major-13-death',{long:`Смерть в Таро почти всегда говорит не о буквальной смерти, а о завершении формы, которая больше не может жить прежним образом. В образе Уэйта важно движение вперед: старое уходит, чтобы освободить место новому. Карта показывает конец этапа, разрыв привычки, глубокую трансформацию и очищение от отжившего. Новичку важно читать ее как честное закрытие цикла, а не как катастрофу.`,love:`Конец старой динамики, связь либо меняется, либо завершается.`,work:`Закрытие проекта, смена роли, увольнение, реорганизация.`,advice:`Назови, что уже закончилось, и не тащи это дальше.`,rev:`цепляние за отжившее, страх перемен, затянутая развязка или трансформация, которой сопротивляются.`}],
['major-14-temperance',{long:`Умеренность показывает смешивание потоков и точную пропорцию. Уэйт связывает ее с гармонизацией, исцелением, экономией сил и внутренней алхимией. Это карта не слабости, а мастерства меры: соединить разные элементы так, чтобы они начали работать вместе. Новичку стоит искать, где ситуация просит не максимума, а правильной настройки и бережного темпа.`,love:`Примирение, восстановление доверия, мягкое согласование различий.`,work:`Настройка процесса, интеграция, командная совместимость, лечение перегруза.`,advice:`Выбирай не максимум, а точную меру.`,rev:`крайность, нетерпение, несогласованность частей или попытка лечить ситуацию неправильной дозой.`}],
['major-15-devil',{long:`Дьявол показывает цепи, которые держатся не только страхом, но и удовольствием, выгодой, привычкой или стыдом. Уэйт связывает карту с материальностью, зависимостью, искушением и несвободой. В раскладе она просит честно увидеть, что именно управляет человеком: желание, ревность, деньги, власть, статус или страх. Новичку важно не морализировать, а искать механизм привязки.`,love:`Сильная химия, зависимость, ревность, контроль, токсичная связка.`,work:`Деньги с условием, токсичная власть, зависимость от статуса, соблазн короткой выгоды.`,advice:`Сначала назови цепь и выгоду, из-за которой ты ее держишь.`,rev:`ослабление цепи, отрицание зависимости, стыд или попытка освободиться без честного признания причины.`}],
['major-16-tower',{long:`Башня поражена молнией: конструкция рушится, потому что ее фундамент не выдерживает правды. Уэйт дает здесь образ внезапного разрушения иллюзий, освобождения и резкой перестройки. Карта неприятна, но часто очищает пространство от того, что держалось на самообмане. Новичку стоит спрашивать: какая конструкция была слабой еще до удара и что теперь нельзя делать вид, будто все нормально.`,love:`Резкий разговор, вскрытие правды, слом иллюзии.`,work:`Кризис проекта, увольнение, аварийная перестройка, конфликт с системой.`,advice:`Не спасай фасад, если проблема в фундаменте.`,rev:`отложенный кризис, страх признать разрушение, попытка удержать фасад или мягкий вариант неизбежного слома.`}],
['major-17-star',{long:`Звезда идет после Башни и приносит мягкое восстановление, чистоту намерения и доверие будущему. Уэйт связывает ее с надеждой, духовной поддержкой, красотой и светом после разрушения. Это не карта мгновенного результата, а карта направления: впереди есть смысл, даже если путь еще длинный. Новичку стоит читать ее как исцеление, вдохновение и возвращение связи с собой.`,love:`Нежность, исцеление после боли, надежда, доверие без давления.`,work:`Творческий проект, публичность, восстановление после провала, долгий путь к признанию.`,advice:`Дай надежде стать направлением, а не требуй немедленного доказательства.`,rev:`потеря веры, усталость, разочарование или мечта, которая пока не подкреплена живым действием.`}],
['major-18-moon',{long:`Луна ведет по ночной дороге между водой, животными инстинктами и неясными очертаниями. Уэйт связывает ее с иллюзиями, скрытыми влияниями, тревогой, снами и глубинной психикой. Карта не отменяет интуицию, но предупреждает: страх может звучать очень похожим голосом. Новичку важно проверять факты и не делать окончательных выводов в состоянии тумана.`,love:`Неясность, ревность, фантазии, страхи, недосказанность.`,work:`Мутные условия, скрытые риски, недостаток данных, эмоциональная усталость.`,advice:`В тумане не ускоряй шаг.`,rev:`рассеивание тумана, вскрытие иллюзии, тревога, которую пора проверить фактами.`}],
['major-19-sun',{long:`Солнце делает ситуацию видимой, теплой и простой. Уэйт связывает его с радостью, жизненной силой, ясностью, успехом и открытым проявлением. После ночи Луны появляется возможность видеть вещи прямо, без лишней драмы и скрытых подтекстов. Новичку стоит читать Солнце как карту результата, доверия, здоровья, признания и честного света.`,love:`Тепло, искренность, радость друг от друга, простота без игр.`,work:`Успех, признание, ясный результат, презентация, завершение в плюс.`,advice:`Не усложняй там, где уже ясно.`,rev:`ослабленная радость, слепой оптимизм, эгоцентризм или успех, который еще не до конца проявлен.`}],
['major-20-judgement',{long:`Суд показывает пробуждение, зов и пересмотр прошлого перед новым уровнем. Уэйт дает образ людей, которые поднимаются на звук трубы: опыт уже не просто случился, он требует ответа. В раскладе карта говорит об итогах, возвращении темы, важном решении, призвании, освобождении от старой вины или публичной оценке. Новичку стоит видеть здесь не наказание, а момент пробуждения ответственности.`,love:`Разговор по итогам прошлого, прощение, решение о статусе, возвращение важной темы.`,work:`Аттестация, релиз, смена призвания, публичная оценка.`,advice:`Услышь зов опыта и ответь действием.`,rev:`страх решения, вина, застревание в прошлом или отказ услышать очевидный зов к перемене.`}],
['major-21-world',{long:`Мир завершает путь старших арканов и собирает разрозненный опыт в целую форму. Уэйт связывает эту карту с завершением, полнотой, успехом, путешествием и интеграцией. Это не просто конец, а ощущение, что урок действительно пройден и элементы нашли свое место. Новичку стоит читать Мир как зрелый результат, оформление цикла и готовность перейти на следующий круг уже другим человеком.`,love:`Зрелое завершение этапа, оформление союза, спокойное признание результата.`,work:`Завершенный проект, выпуск продукта, диплом, признание, международный контекст.`,advice:`Закрой круг достойно и не тащи старую задачу дальше.`,rev:`незакрытый финал, страх завершить, последний шаг не оформлен или цикл завершен только внешне.`}],
['wands-01-ace',{long:`Туз Жезлов у Уэйта это рука из облака, которая держит живой посох с листьями. Карта показывает первичный огонь: желание начать, импульс, идею, физическую энергию, творческую искру. Новичку важно видеть, что это еще не готовый проект, а семя действия: у человека появляется топливо, но его нужно направить. Смотри на свежие побеги на жезле: потенциал живой, но он требует движения, смелости и среды.`,love:`В отношениях это искра, сексуальное притяжение, желание проявиться, первый шаг или возвращение живости.`,work:`В работе это идея проекта, предпринимательский импульс, новый запуск, вдохновение или желание быстро проверить гипотезу.`,advice:`Поймай импульс и оформи его в первое действие, пока огонь не ушел в фантазию.`,rev:`погасшая искра, задержка старта, страх проявиться, импульсивность без формы.`}],
['wands-02-two',{long:`Двойка Жезлов показывает человека с глобусом в руке: он уже имеет опору, но смотрит за пределы привычной территории. Это карта выбора направления, планирования, расширения и внутреннего беспокойства: оставаться там, где безопасно, или рискнуть большим. В отличие от Туза, здесь огонь уже не вспышка, а стратегия. Читай карту через вопрос: человек действительно готов выйти за ворота или пока только мечтает у стены.`,love:`В отношениях это выбор сценария, дистанция, взгляд на перспективу пары, желание большего пространства.`,work:`В работе это стратегия, оценка рынка, план роста, выбор между стабильностью и расширением.`,advice:`Не торопись прыгать: сначала выбери направление и цену выхода из привычного.`,rev:`нерешительность, страх масштаба, план без действия, зависание между двумя вариантами.`}],
['wands-03-three',{long:`Тройка Жезлов показывает фигуру, которая смотрит на корабли вдалеке. Первый шаг уже сделан, и теперь человек ждет ответа от мира: результаты начали уходить наружу. Это карта расширения, первых плодов, дальнего горизонта, партнерств и уверенного ожидания. Новичку стоит смотреть не только на ожидание, но и на масштаб: карта часто говорит, что ситуация уже вышла за пределы личной комнаты и требует думать шире.`,love:`В отношениях это перспектива развития, ожидание ответа, связь на расстоянии или планы на будущее.`,work:`В работе это экспорт идеи, первые результаты запуска, переговоры, расширение аудитории или партнерский канал.`,advice:`Смотри дальше ближайшей реакции: твой шаг уже работает на дистанции.`,rev:`задержка результата, узкий горизонт, разочарование ожиданием или проект не выходит наружу.`}],
['wands-04-four',{long:`Четверка Жезлов изображает праздничную арку и людей, которые встречают завершение важного этапа. Это карта опоры, дома, праздника, признания и момента, когда огонь получает устойчивую форму. В чтении она часто показывает не финал всей истории, а безопасную площадку, где можно выдохнуть и отметить пройденное. Для новичка важна атмосфера карты: здесь энергия не соревнуется, а собирает людей вокруг общего очага.`,love:`В отношениях это радость, встреча, семейность, ощущение дома, праздник или шаг к устойчивому союзу.`,work:`В работе это успешный этап, командное достижение, открытие, презентация, корпоративное признание.`,advice:`Отметь пройденное и закрепи опору, прежде чем идти в следующий рывок.`,rev:`праздник откладывается, нет ощущения дома, нестабильная база, радость не разделяется.`}],
['wands-05-five',{long:`Пятерка Жезлов показывает группу людей с поднятыми жезлами: это не смертельная битва, а шумная конкуренция, тренировка, столкновение воль. Карта говорит о конфликте интересов, борьбе за место, хаосе инициатив и ситуации, где каждый действует, но общего ритма нет. Новичку важно не пугаться: иногда это здоровая проверка силы, а не разрушение. Вопрос в том, есть ли правила игры и умеют ли участники слышать друг друга.`,love:`В отношениях это споры, соревнование характеров, борьба за внимание или много несогласованных импульсов.`,work:`В работе это конкуренция, мозговой штурм без модерации, конфликт ролей, активная среда.`,advice:`Введи правила боя: энергия есть, но ей нужен общий формат.`,rev:`скрытый конфликт, избегание спора, усталость от борьбы или хаос, который уже мешает результату.`}],
['wands-06-six',{long:`Шестерка Жезлов показывает всадника с венком победителя. Это карта признания, видимого успеха, поддержки группы и момента, когда усилие замечают. В отличие от Четверки, здесь не домашний праздник, а публичное движение после победы. Новичку стоит читать ее как социальный сигнал: кто видит победу, кто поддерживает, кому важно признание и не превращается ли успех в зависимость от аплодисментов.`,love:`В отношениях это гордость за партнера, публичное признание, победа после трудностей или желание быть выбранным.`,work:`В работе это успешная презентация, повышение статуса, хороший отзыв, лидерство, победа в конкурсе.`,advice:`Прими признание, но не делай аплодисменты единственным источником силы.`,rev:`успех не признали, страх сцены, завышенная гордость, победа оказалась хрупкой.`}],
['wands-07-seven',{long:`Семерка Жезлов показывает человека на высоте, который защищает свою позицию от жезлов снизу. Это карта давления, конкуренции и необходимости отстоять занятое место. Здесь важно преимущество позиции: человек выше, но ему нужно быть собранным. Новичку полезно спрашивать: что именно защищается, стоит ли это усилий и не расходует ли человек всю энергию на оборону вместо развития.`,love:`В отношениях это защита границ, борьба за связь, давление извне или необходимость сказать твердое нет.`,work:`В работе это конкуренты, защита решения, спор с командой, необходимость удержать позицию.`,advice:`Определи, что стоит защищать, и не трать силы на каждый летящий жезл.`,rev:`сдача позиции, усталость от защиты, агрессивная оборона, неясно за что идет борьба.`}],
['wands-08-eight',{long:`Восьмерка Жезлов показывает летящие жезлы: люди исчезают из сцены, остается чистое движение. Это карта скорости, сообщений, развития событий, поездок и процесса, который уже запущен. Новичку важно понять: здесь мало контроля и много темпа. Карта часто говорит, что ситуация ускоряется, ответы приходят быстро, а промедление может стоить момента.`,love:`В отношениях это быстрый обмен сообщениями, внезапное развитие, страсть на расстоянии или стремительное сближение.`,work:`В работе это дедлайн, быстрые задачи, коммуникации, запуск рассылки, логистика, резкий прогресс.`,advice:`Действуй в темпе ситуации, но следи, куда летят твои жезлы.`,rev:`задержки, сбои связи, суета, слишком быстрое развитие без осмысления.`}],
['wands-09-nine',{long:`Девятка Жезлов показывает раненого, но стоящего человека с рядом жезлов за спиной. Это карта опыта, настороженности, выносливости и последней защиты перед завершением цикла. Он уже многое прошел, поэтому не наивен, но может стать слишком подозрительным. Новичку стоит смотреть на повязку и взгляд: карта говорит не только о силе, но и о цене, которую человек заплатил за стойкость.`,love:`В отношениях это осторожность после боли, проверка доверия, защитная позиция или готовность не сдаться.`,work:`В работе это выгорание на финише, защита проекта, накопленный опыт, необходимость выдержать последний этап.`,advice:`Береги силы: стойкость нужна, но не превращай каждую ситуацию в осаду.`,rev:`паранойя, истощение, отказ продолжать, слишком толстая броня или повторная травма.`}],
['wands-10-ten',{long:`Десятка Жезлов показывает человека, несущего тяжелую связку жезлов к городу. Это карта ответственности, перегруза и ситуации, где энергия превратилась в обязанность. В начале масти был вдохновляющий импульс, а теперь человек несет слишком много сам. Новичку важно видеть город впереди: цель близко, но способ движения может быть невыносимым.`,love:`В отношениях это усталость от ответственности, роль того, кто тащит связь, быт или эмоциональную нагрузку.`,work:`В работе это перегруз, дедлайны, слишком много задач, руководительская ноша или проект на последнем рывке.`,advice:`Донеси важное, но пересобери нагрузку: не все жезлы обязаны быть твоими.`,rev:`сброс нагрузки, отказ от обязанностей, выгорание, ноша стала бессмысленной.`}],
['wands-11-page',{long:`Паж Жезлов стоит с посохом и смотрит на него как на источник нового приключения. Это молодой огонь: любопытство, новость, приглашение, творческий порыв, желание попробовать себя. Карта не обещает зрелого мастерства, но показывает живую искру обучения. Новичку полезно читать Пажа как вопрос: что меня зажигает и где я готов учиться через действие, даже если пока неловко.`,love:`В отношениях это флирт, сообщение, легкий интерес, игривость, молодой энтузиазм.`,work:`В работе это новая идея, стажировка, первая попытка, творческий бриф, желание заявить о себе.`,advice:`Разреши себе быть учеником, но не путай восторг с завершенным результатом.`,rev:`незрелость, хвастовство, потеря интереса, новость не подтверждается делом.`}],
['wands-12-knight',{long:`Рыцарь Жезлов мчится вперед: это огонь в движении, смелость, страсть, приключение и риск. Карта показывает человека или процесс, который не любит ждать и быстро входит в действие. Его сила в решительности, слабость в нетерпении. Новичку важно смотреть, управляет ли рыцарь конем или просто несется за собственным импульсом.`,love:`В отношениях это страсть, внезапный приход, яркий роман, но иногда нестабильность и исчезновения.`,work:`В работе это быстрый запуск, командировка, кризисный рывок, предпринимательский азарт, смена направления.`,advice:`Используй скорость, но проверь маршрут и последствия.`,rev:`импульсивность, вспыльчивость, срыв планов, человек загорается и быстро остывает.`}],
['wands-13-queen',{long:`Королева Жезлов сидит с подсолнухом и черной кошкой: это зрелый огонь, харизма, тепло, независимость и интуитивная сила. Она не доказывает право сиять, она просто присутствует уверенно. Карта часто говорит о привлекательности, лидерстве через вдохновение и способности поддерживать огонь в других. Новичку стоит помнить: ее власть не жесткая, а магнетическая.`,love:`В отношениях это страсть, уверенность, притяжение, теплота, самостоятельность и личная яркость.`,work:`В работе это публичность, лидерство, креативное управление, личный бренд, вдохновляющая фигура.`,advice:`Действуй из внутреннего огня и не уменьшай себя, чтобы быть удобнее.`,rev:`ревность, драматичность, зависимость от внимания, подавленная харизма или усталость быть сильной.`}],
['wands-14-king',{long:`Король Жезлов держит посох как символ управляемого огня. Это лидер, стратег, предприниматель, человек видения и личной воли. В отличие от Рыцаря, он не просто мчится: он задает направление другим. Новичку важно смотреть, как карта говорит о зрелой ответственности за энергию: вдохновить, организовать, повести, но не сжечь людей своим темпом.`,love:`В отношениях это сильная позиция, страсть, инициативность, щедрость, но иногда доминирование.`,work:`В работе это руководитель, владелец проекта, стратегия, риск, запуск большой идеи, управление командой.`,advice:`Возглавь процесс, но помни: настоящий огонь греет, а не только командует.`,rev:`авторитарность, вспыльчивость, самолюбие, обещания больше возможностей или выгоревшее лидерство.`}],
['cups-01-ace',{long:`Туз Кубков у Уэйта показывает чашу, из которой переливается вода: это источник чувства, любви, сострадания, вдохновения и внутреннего обновления. Карта не обязательно про роман, она шире: сердце открывается, эмоция начинает течь, появляется способность принимать и отдавать. Новичку важно смотреть на переполненность чаши: чувство есть, но его нужно бережно вместить.`,love:`В отношениях это влюбленность, примирение, нежность, новое чувство или готовность открыться.`,work:`В работе это творческое вдохновение, приятная атмосфера, проект от сердца, эмоциональная мотивация.`,advice:`Не анализируй живое чувство до смерти, дай ему безопасную форму.`,rev:`закрытое сердце, эмоциональный перелив, обида, чувство есть, но не находит выхода.`}],
['cups-02-two',{long:`Двойка Кубков показывает двух людей, которые обмениваются чашами. Это карта взаимности, симпатии, договора сердца и равного эмоционального обмена. В отличие от Влюбленных, здесь меньше судьбоносного выбора и больше конкретного контакта между двумя. Новичку важно смотреть, есть ли обмен в обе стороны: карта хороша, когда чувства встречаются, а не текут в пустоту.`,love:`В отношениях это взаимная симпатия, начало пары, примирение, честный эмоциональный контакт.`,work:`В работе это партнерство, доверительный союз, удачная встреча, согласование интересов.`,advice:`Смотри на взаимность: хороший союз строится на обмене, а не на догадках.`,rev:`неравный обмен, охлаждение, недоверие, примирение не состоялось или чувства расходятся.`}],
['cups-03-three',{long:`Тройка Кубков изображает праздник трех женщин с поднятыми чашами. Это карта дружбы, радости, поддержки, общности и эмоционального празднования. Она часто говорит не о глубокой парной драме, а о круге людей, где чувства легче и светлее. Новичку стоит смотреть на тему сообщества: кто рядом, с кем можно разделить радость и не превращается ли веселье в поверхностность.`,love:`В отношениях это радость общения, свидание в легком кругу, поддержка друзей, иногда тема третьих лиц.`,work:`В работе это командная победа, приятный коллектив, мероприятие, креативная группа.`,advice:`Раздели радость с людьми, но не прячь серьезный вопрос за вечным праздником.`,rev:`поверхностность, сплетни, лишний человек в ситуации, усталость от компании или праздник не радует.`}],
['cups-04-four',{long:`Четверка Кубков показывает человека под деревом, который не замечает чашу, поданную из облака. Это карта эмоциональной закрытости, пресыщения, скуки, внутренней паузы и отказа от очевидного предложения. Новичку важно видеть, что карта не всегда плохая: иногда человеку действительно нужно отстраниться и понять, чего он хочет. Но если пауза затянулась, шанс проходит мимо.`,love:`В отношениях это скука, закрытость, обида, нежелание отвечать на предложение или эмоциональная усталость.`,work:`В работе это потеря мотивации, неинтересные предложения, творческий застой, апатия.`,advice:`Проверь, ты правда не хочешь эту чашу или просто закрылся от всего.`,rev:`выход из апатии, новый интерес, шанс замечен поздно, эмоциональное пробуждение.`}],
['cups-05-five',{long:`Пятерка Кубков показывает фигуру в черном плаще, которая смотрит на три пролитые чаши и не замечает две целые за спиной. Это карта потери, сожаления, разочарования и фокуса на том, что не получилось. Новичку важно читать ее мягко: боль настоящая, но картина неполная. За фигурой есть мост и оставшиеся чаши, значит путь восстановления существует.`,love:`В отношениях это сожаление, расставание, обида, чувство утраты или фиксация на разочаровании.`,work:`В работе это провал, упущенная возможность, недовольство результатом, но не полный конец ресурсов.`,advice:`Признай потерю, потом повернись к тому, что еще можно сохранить.`,rev:`принятие утраты, выход из сожаления, возвращение надежды или отказ отпустить прошлое.`}],
['cups-06-six',{long:`Шестерка Кубков показывает детей, цветы в чашах и атмосферу старого двора. Это карта памяти, прошлого, доброты, детской простоты, подарка и эмоционального корня. Она может быть очень теплой, но иногда указывает на идеализацию прошлого. Новичку стоит спрашивать: прошлое поддерживает человека или удерживает его в прежнем возрасте.`,love:`В отношениях это ностальгия, возвращение человека, нежность, давняя связь, детская искренность.`,work:`В работе это старые контакты, привычный формат, помощь из прошлого, обучение через базовые навыки.`,advice:`Возьми из прошлого тепло и опыт, но не живи в нем вместо настоящего.`,rev:`застревание в прошлом, инфантильность, идеализация бывшего, трудность повзрослеть.`}],
['cups-07-seven',{long:`Семерка Кубков показывает фигуру перед облаком с разными образами в чашах. Это карта фантазий, вариантов, соблазнов, мечты и путаницы желаний. Здесь много возможностей, но не все они реальны и полезны. Новичку важно читать карту как проверку выбора: что является настоящим желанием, что страхом, что иллюзией, а что красивой упаковкой без содержания.`,love:`В отношениях это фантазии, идеализация, несколько вариантов, неопределенность чувств или розовые очки.`,work:`В работе это множество идей, распыление, выбор направления, соблазн красивого, но непроверенного проекта.`,advice:`Сними туман с вариантов: выбери не самую яркую чашу, а самую живую и реальную.`,rev:`прояснение выбора, отказ от иллюзий, либо наоборот хаос фантазий стал сильнее.`}],
['cups-08-eight',{long:`Восьмерка Кубков показывает человека, который уходит от стоящих чаш в ночь. Это карта эмоционального ухода, поиска глубины и отказа от того, что внешне может быть нормальным, но внутренне уже не питает. Новичку важно видеть: чаши не разбиты, но человек все равно уходит. Значит вопрос не в катастрофе, а в честности с собственным сердцем.`,love:`В отношениях это уход, дистанция, разочарование без скандала, поиск большего смысла.`,work:`В работе это смена направления, потеря эмоциональной вовлеченности, уход из комфортного, но пустого места.`,advice:`Если чаши полны только снаружи, честно признай, куда зовет внутренняя пустота.`,rev:`страх уйти, возвращение, зависание в старом, уход без понимания причины.`}],
['cups-09-nine',{long:`Девятка Кубков показывает человека перед рядом чаш, довольного достигнутым. Это карта удовлетворения, желания, личного комфорта, удовольствия и момента, когда можно сказать: мне хорошо. Но в ней есть и вопрос меры: радость может стать самодовольством. Новичку стоит смотреть на позу человека: он наслаждается, но закрыт ли он для обмена с другими.`,love:`В отношениях это удовольствие, исполнение желания, приятное свидание, эмоциональное насыщение.`,work:`В работе это желанный результат, бонус, комфорт, удачное завершение личной цели.`,advice:`Позволь себе радоваться, но не превращай счастье в витрину эго.`,rev:`желание не исполнилось, пустое удовольствие, переедание эмоциями, самодовольство или разочарование.`}],
['cups-10-ten',{long:`Десятка Кубков показывает семью, радугу из чаш и общий эмоциональный купол счастья. Это карта гармонии, семьи, общего будущего, эмоциональной полноты и разделенной радости. В отличие от Девятки, здесь счастье не индивидуальное, а общее. Новичку важно видеть, что карта говорит о согласии людей и образе дома, но в перевернутом виде может показать несоответствие красивой картинки реальной близости.`,love:`В отношениях это семейность, любовь, общий дом, эмоциональная безопасность, счастливый этап.`,work:`В работе это гармоничная команда, общий успех, проект с человеческим смыслом, благоприятная атмосфера.`,advice:`Строй не только личное удовольствие, но и пространство, где радость можно разделить.`,rev:`идеальная картинка трещит, семейное напряжение, разлад ожиданий или счастье показное.`}],
['cups-11-page',{long:`Паж Кубков держит чашу с рыбой: это неожиданное сообщение из мира чувств, творческая странность, признание, нежность и эмоциональная открытость новичка. Карта часто приносит весть, извинение, комплимент или маленький знак симпатии. Новичку важно не требовать от Пажа взрослой устойчивости: он искренний, но еще учится понимать свои чувства.`,love:`В отношениях это сообщение, признание, нежный флирт, извинение, робкая симпатия.`,work:`В работе это творческая идея, вдохновение, обучение эмпатии, проект с воображением.`,advice:`Прими мягкий сигнал, но проверь, станет ли он зрелым действием.`,rev:`эмоциональная незрелость, обидчивость, странный сигнал, фантазия вместо чувства.`}],
['cups-12-knight',{long:`Рыцарь Кубков едет с чашей как посланник чувства, предложения и романтического жеста. Это карта приглашения, признания, идеала, поэзии, мечты и движения сердца. Его сила в тонкости и красоте, слабость в склонности к идеализации. Новичку стоит смотреть, несет ли рыцарь реальную чашу или только красивый образ, который приятно слушать.`,love:`В отношениях это романтическое предложение, свидание, признание, мягкое ухаживание.`,work:`В работе это творческий проект, дипломатия, предложение, эстетика, работа с эмоциями аудитории.`,advice:`Иди за чувством, но не забывай проверять поступки за красивыми словами.`,rev:`идеализация, непостоянство, обещания без опоры, эмоциональная манипуляция.`}],
['cups-13-queen',{long:`Королева Кубков сидит у воды и держит закрытую украшенную чашу. Это зрелая эмоциональность, интуиция, забота, тонкое восприятие и способность быть рядом с чувствами, не разрушаясь в них. Она глубже Пажа и спокойнее Рыцаря: ее сила в внутренней чуткости. Новичку важно видеть закрытую чашу: не все чувства нужно сразу выливать наружу, иногда их нужно бережно хранить.`,love:`В отношениях это глубокая эмпатия, забота, нежность, интуитивное понимание партнера.`,work:`В работе это поддерживающая роль, психология, творчество, работа с атмосферой, забота о людях.`,advice:`Доверяй чувствам, но сохраняй границы своей чаши.`,rev:`эмоциональное растворение, тревожность, созависимость, манипуляция заботой или закрытость.`}],
['cups-14-king',{long:`Король Кубков сидит над водой, сохраняя спокойствие среди эмоциональной стихии. Это зрелое владение чувствами, мудрость, дипломатия, способность сочувствовать и не тонуть. Он не подавляет эмоции, а управляет ими достойно. Новичку стоит читать его как фигуру эмоциональной ответственности: чувство есть, но оно не разрушает решения.`,love:`В отношениях это зрелая забота, надежная эмоциональность, спокойная любовь, умение говорить мягко.`,work:`В работе это дипломатия, управление людьми, переговоры, помощь, творческое руководство.`,advice:`Будь мягким, но устойчивым: зрелое чувство не обязано быть бурей.`,rev:`эмоциональная закрытость, пассивность, манипуляция чувствами или видимое спокойствие при внутреннем шторме.`}],
['swords-01-ace',{long:`Туз Мечей показывает руку с мечом и короной: это ясная мысль, слово, решение, правда и интеллектуальный прорыв. Карта может быть холодной, но очищающей: меч отделяет важное от лишнего. Новичку важно помнить, что Туз Мечей не про комфорт, а про точность. Он дает шанс назвать вещи своими именами, даже если это режет иллюзии.`,love:`В отношениях это честный разговор, ясность, признание факта, иногда резкое прояснение.`,work:`В работе это решение, документ, стратегия, анализ, начало интеллектуального проекта.`,advice:`Сформулируй правду коротко и точно, не смягчая ее до неясности.`,rev:`путаница, резкие слова, ложный вывод, правда используется как оружие.`}],
['swords-02-two',{long:`Двойка Мечей показывает женщину с завязанными глазами и двумя мечами на груди. Это карта защиты, нерешительности, внутреннего тупика и попытки удержать равновесие между двумя неприятными вариантами. Вода за спиной напоминает, что чувства есть, но человек их отрезал ради контроля. Новичку стоит спрашивать: какую информацию не хотят видеть и какое решение откладывается.`,love:`В отношениях это молчание, блок, нежелание выбирать, закрытость от чувств.`,work:`В работе это пауза в решении, противоречивые данные, нейтралитет, дипломатическое замораживание.`,advice:`Сними повязку: выбор не исчезнет, если его не смотреть.`,rev:`решение прорвалось, защита ослабла, растерянность или отказ больше молчать.`}],
['swords-03-three',{long:`Тройка Мечей показывает сердце, пронзенное мечами, на фоне дождя. Это карта боли, разрыва, болезненной правды, горя и слов, которые ранят. Она не обязательно означает окончательную катастрофу, но показывает момент, где ум и факт пробивают эмоциональную защиту. Новичку важно не сглаживать карту: боль нужно признать, иначе она уйдет глубже.`,love:`В отношениях это сердечная боль, разрыв, измена, обидные слова, честное, но тяжелое понимание.`,work:`В работе это неприятная новость, отказ, критика, болезненный разбор ошибок.`,advice:`Назови боль честно, но не делай из одного удара весь смысл будущего.`,rev:`заживление, вытесненная боль, повторное вскрытие раны или освобождение через правду.`}],
['swords-04-four',{long:`Четверка Мечей показывает лежащую фигуру в покое, как в часовне или месте восстановления. Это карта паузы, отдыха, тишины после борьбы, восстановления ума и временного выхода из конфликта. Новичку важно не читать ее как лень: это лечебная остановка, где мечи отложены, чтобы человек не сломался. Вопрос карты: достаточно ли ты отдохнул, чтобы думать ясно.`,love:`В отношениях это пауза, молчание, дистанция для восстановления, необходимость остыть.`,work:`В работе это отпуск, больничный, остановка проекта, период анализа без активных действий.`,advice:`Сначала восстанови нервную систему, потом принимай решение.`,rev:`покой нарушен, восстановление затянулось, тревога не дает отдыхать или пора возвращаться к жизни.`}],
['swords-05-five',{long:`Пятерка Мечей показывает победителя с мечами и уходящих людей. Это карта конфликта, победы с неприятным привкусом, манипуляции, унижения или ситуации, где выигрыш разрушает отношения. Новичку важно смотреть не только на того, кто победил, но и на поле после спора. Иногда карта спрашивает: стоила ли победа того, что осталось после нее.`,love:`В отношениях это ссора, колкие слова, борьба за правоту, обида после победы одного из партнеров.`,work:`В работе это токсичная конкуренция, офисная интрига, спор, где важнее победить, чем решить.`,advice:`Выбирай не только победу, но и последствия, с которыми останешься.`,rev:`отказ от борьбы, попытка примирения, осознание ущерба или скрытая обида после конфликта.`}],
['swords-06-six',{long:`Шестерка Мечей показывает лодку, которая увозит людей через воду. Это карта перехода, ухода от трудного берега, восстановления после конфликта и движения к более спокойному состоянию. Мечи в лодке напоминают: опыт и мысли едут вместе, их нельзя просто выбросить. Новичку стоит читать карту как мягкую, но грустную смену места или состояния.`,love:`В отношениях это дистанция, попытка выйти из конфликта, переезд, терапевтический переход.`,work:`В работе это смена команды, переходный период, миграция, уход от кризиса к более спокойной системе.`,advice:`Переходи на другой берег, но не притворяйся, что багаж исчез сам.`,rev:`застревание между берегами, трудный переезд, возвращение к старым проблемам.`}],
['swords-07-seven',{long:`Семерка Мечей показывает человека, который уносит мечи тайком. Это карта стратегии, скрытого хода, обходного пути, хитрости, недоговоренности или желания избежать прямого столкновения. Она не всегда про обман, но всегда про непрямое действие. Новичку важно спросить: это умная тактика в сложной ситуации или нечестность, которая потом разрушит доверие.`,love:`В отношениях это недоговоренность, скрытые мотивы, избегание разговора, тайная стратегия.`,work:`В работе это обход правил, осторожная тактика, кулуарные решения, риск нечестной игры.`,advice:`Проверь, твоя стратегия защищает тебя или делает ситуацию грязнее.`,rev:`секрет раскрыт, отказ от хитрости, самообман, стратегия перестала работать.`}],
['swords-08-eight',{long:`Восьмерка Мечей показывает связанную женщину среди мечей, но проход вокруг нее не полностью закрыт. Это карта ограничения, страха, ментальной ловушки и ощущения беспомощности. Часто проблема не только во внешних обстоятельствах, но и в том, как человек описывает их себе. Новичку важно заметить: повязка и путы выглядят сильнее, чем реальная невозможность шага.`,love:`В отношениях это страх сказать правду, ощущение ловушки, зависимость от чужого мнения.`,work:`В работе это бюрократические ограничения, страх ошибки, ментальный блок, невозможность увидеть вариант.`,advice:`Назови реальные ограничения отдельно от тех, которые создал страх.`,rev:`освобождение, снятие повязки, выход из ловушки или усиление паники перед шагом.`}],
['swords-09-nine',{long:`Девятка Мечей показывает человека в постели, закрывающего лицо, а над ним висят мечи. Это карта тревоги, бессонницы, вины, навязчивых мыслей и внутренней ночи. Часто ситуация уже не происходит снаружи, но продолжает мучить внутри. Новичку важно читать карту бережно: здесь нужен не совет не думай, а разделение фактов, страха и самонаказания.`,love:`В отношениях это тревога, вина, страх потерять, болезненные мысли ночью, переживание сказанных слов.`,work:`В работе это стресс, страх провала, перегруз мыслей, ожидание плохой новости.`,advice:`Вынеси мысли на свет: проверь факты и не оставляй страх один на один с ночью.`,rev:`тревога ослабевает, признание проблемы, либо мысли становятся навязчивее и требуют помощи.`}],
['swords-10-ten',{long:`Десятка Мечей показывает фигуру, пронзенную десятью мечами, и рассвет на горизонте. Это карта жесткого финала, предельной ментальной боли, поражения старого сценария. Она драматична, но в ней есть конец мучительного цикла: дальше хуже уже не становится, начинается рассвет. Новичку важно не пугаться изображения, а увидеть завершение истории, которую больше нельзя продолжать прежним способом.`,love:`В отношениях это болезненный финал, чувство предательства, точка после долгого напряжения.`,work:`В работе это закрытие проекта, увольнение, провал стратегии, конец иллюзии контроля.`,advice:`Признай финал и не продолжай лежать под мечами из верности прошлому.`,rev:`выход после поражения, затяжной финал, отказ принять конец или восстановление после дна.`}],
['swords-11-page',{long:`Паж Мечей стоит настороженно с поднятым мечом. Это молодой ум: наблюдение, вопросы, проверка фактов, любопытство, новость, иногда подозрительность. Карта хороша для обучения и анализа, но может быть резкой в словах. Новичку важно видеть в Паже не врага, а начинающего мыслителя, который учится отличать правду от шума.`,love:`В отношениях это наблюдение, переписка, вопросы, осторожность, иногда слежка или колкость.`,work:`В работе это исследование, сбор данных, обучение, проверка документов, критическое мышление.`,advice:`Задавай вопросы, но не превращай любопытство в допрос.`,rev:`сплетни, резкость, поверхностные выводы, недостоверная информация, тревожный контроль.`}],
['swords-12-knight',{long:`Рыцарь Мечей мчится вперед с поднятым мечом: это мысль, ставшая атакой. Карта говорит о скорости, решительности, споре, резком действии, защите идеи и иногда о конфликте без паузы. Его сила в смелости назвать и прорваться, слабость в слепоте к последствиям. Новичку важно спрашивать: это точный прорыв или человек просто рубит все на ходу.`,love:`В отношениях это резкий разговор, напор, спор, внезапное сообщение, требование ясности.`,work:`В работе это срочное решение, кризисная коммуникация, защита позиции, быстрый анализ, конфликт.`,advice:`Используй ясность меча, но замедлись настолько, чтобы не ранить лишнее.`,rev:`агрессия, поспешные выводы, словесная атака, хаотичное движение или срыв.`}],
['swords-13-queen',{long:`Королева Мечей сидит с поднятым мечом и открытой ладонью: она сочетает ясность границы и готовность слушать. Это зрелый ум, честность, независимость, опыт боли, способность отделять факт от эмоции. Карта часто показывает человека, который не купится на красивые слова без сути. Новичку важно не делать ее холодной злодейкой: ее прямота родилась из опыта, а не из отсутствия сердца.`,love:`В отношениях это честный разговор, границы, трезвость, независимость, проверка слов делами.`,work:`В работе это экспертность, редактура, юридическая или аналитическая позиция, точное решение.`,advice:`Говори ясно и держи границу, но оставь место человеческому теплу.`,rev:`жесткость, горечь, критика ради контроля, эмоциональная закрытость или страх уязвимости.`}],
['swords-14-king',{long:`Король Мечей держит меч как символ закона мысли, решения и авторитета. Это зрелый интеллект, структура, справедливость, стратегия, способность выносить суждение без эмоционального шума. Он полезен там, где нужно правило, договор или точная позиция. Новичку стоит смотреть, не становится ли ясность жестокостью: сильный Король Мечей служит правде, а не своему превосходству.`,love:`В отношениях это рациональный разговор, дистанция, честные правила, иногда эмоциональная сухость.`,work:`В работе это руководитель, юрист, аналитик, архитектор решения, стратегия, регламент.`,advice:`Прими решение на основе фактов и не прячься за холодностью.`,rev:`авторитарный ум, холодность, манипуляция правилами, злоупотребление властью слова.`}],
['pentacles-01-ace',{long:`Туз Пентаклей показывает руку с монетой над садовой дорожкой. Это материальный шанс: деньги, ресурс, тело, работа, имущество, практическое начало. В отличие от Туза Жезлов, здесь важна не искра, а возможность воплотить что-то в плотной форме. Новичку стоит смотреть на сад и арку: шанс реален, но нужно пройти путь и вложить труд.`,love:`В отношениях это надежный шаг, забота делом, подарок, телесная близость, шанс на устойчивость.`,work:`В работе это предложение, деньги, новый проект, покупка, контракт, практический ресурс.`,advice:`Возьми шанс руками и преврати его в конкретный план.`,rev:`упущенная возможность, задержка денег, ресурс есть, но не используется, страх вложиться.`}],
['pentacles-02-two',{long:`Двойка Пентаклей показывает человека, который жонглирует двумя монетами на фоне волн. Это карта баланса ресурсов, гибкости, многозадачности, финансовых качелей и необходимости удерживать ритм. Она не всегда плохая: человек справляется, но цена может быть в постоянном напряжении. Новичку важно смотреть на бесконечную ленту вокруг монет: процесс повторяется и требует настройки.`,love:`В отношениях это баланс между личным и общим, нестабильный график, попытка совмещать разные роли.`,work:`В работе это несколько задач, бюджетные качели, гибкое управление ресурсами, временная нестабильность.`,advice:`Удерживай ритм, но реши, что нельзя жонглировать бесконечно.`,rev:`перегруз многозадачностью, финансовая нестабильность, потеря баланса или отказ выбрать приоритет.`}],
['pentacles-03-three',{long:`Тройка Пентаклей показывает мастера, который работает в храме вместе с другими. Это карта навыка, сотрудничества, ремесла, признания компетенции и строительства чего-то долгого. В отличие от Тройки Жезлов, здесь важен не горизонт, а качество исполнения. Новичку стоит смотреть на трех участников: результат появляется там, где мастерство, заказчик и план слышат друг друга.`,love:`В отношениях это работа над союзом, обсуждение быта, вклад каждого, совместное строительство.`,work:`В работе это команда, проектирование, профессиональный рост, оценка качества, обучение у мастеров.`,advice:`Покажи навык и работай с теми, кто уважает качество.`,rev:`плохая координация, недооценка труда, конфликт ролей, работа сделана без мастерства.`}],
['pentacles-04-four',{long:`Четверка Пентаклей показывает человека, который крепко держит монеты и закрывает ими тело. Это карта контроля ресурсов, накопления, безопасности, собственности и страха потерять. Она может говорить о разумной экономии, но также о зажатости. Новичку важно смотреть, насколько человек владеет пентаклями или уже сам стал их заложником.`,love:`В отношениях это удерживание, собственничество, страх открыться, желание стабильности.`,work:`В работе это накопление, контроль бюджета, осторожность, закрытый стиль управления, защита активов.`,advice:`Сохраняй ресурс, но проверь, не стала ли безопасность тюрьмой.`,rev:`потеря контроля, вынужденные траты, отпускание зажатости или страх бедности.`}],
['pentacles-05-five',{long:`Пятерка Пентаклей показывает людей, проходящих мимо освещенного окна. Это карта нехватки, исключенности, болезни, финансовой тревоги и ощущения, что помощь рядом, но недоступна или не замечена. Она тяжелая, но не безнадежная: свет за стеклом говорит о ресурсе. Новичку важно спрашивать, почему герои не входят: гордость, стыд, незнание или реальный запрет.`,love:`В отношениях это одиночество вдвоем, чувство отвержения, нехватка поддержки, трудный период.`,work:`В работе это финансовые потери, сокращение, дефицит ресурсов, страх не справиться.`,advice:`Не проходи мимо помощи из-за стыда, попроси конкретный ресурс.`,rev:`помощь найдена, выход из бедности, восстановление, либо отказ принять поддержку.`}],
['pentacles-06-six',{long:`Шестерка Пентаклей показывает человека, который раздает монеты, держа весы. Это карта помощи, обмена, благотворительности, долга, баланса дающий-получающий. Она хороша, когда помощь справедлива, но может показывать зависимость от того, кто распределяет ресурс. Новичку важно смотреть на весы: вопрос не только в щедрости, но и в равновесии власти.`,love:`В отношениях это поддержка, подарки, неравный вклад, финансовая тема, благодарность или зависимость.`,work:`В работе это оплата, грант, премия, спонсорство, распределение бюджета, наставничество.`,advice:`Помогай или принимай помощь так, чтобы не покупать власть и не продавать достоинство.`,rev:`неравный обмен, долг, манипуляция помощью, жадность или отказ делиться ресурсом.`}],
['pentacles-07-seven',{long:`Семерка Пентаклей показывает человека, который смотрит на выращенные плоды и оценивает результат. Это карта ожидания, терпения, вложенного труда, промежуточной проверки и вопроса: стоит ли продолжать. Здесь нет мгновенной награды, но есть рост. Новичку важно читать ее как момент ревизии: что уже выросло, что требует времени, а что не окупает усилий.`,love:`В отношениях это оценка вложений, терпение, медленный рост, вопрос будущего пары.`,work:`В работе это долгий проект, инвестиции, ожидание результата, проверка эффективности.`,advice:`Оцени урожай честно: не бросай рано, но и не вкладывайся слепо.`,rev:`нетерпение, слабая отдача, усталость ждать, вложения требуют пересмотра.`}],
['pentacles-08-eight',{long:`Восьмерка Пентаклей показывает ремесленника, который последовательно вытачивает монеты. Это карта труда, обучения, практики, дисциплины, ремесла и улучшения навыка через повторение. Она не про быстрый триумф, а про качественную работу день за днем. Новичку стоит видеть: мастерство рождается не от вдохновения, а от терпеливого процесса.`,love:`В отношениях это работа над привычками, ежедневная забота, готовность учиться быть рядом.`,work:`В работе это обучение, практика, кодинг, ремесло, повышение квалификации, внимательное исполнение.`,advice:`Повторяй правильные действия: сейчас выигрывает не талант, а качество процесса.`,rev:`рутина без роста, халтура, усталость от практики, перфекционизм или нежелание учиться.`}],
['pentacles-09-nine',{long:`Девятка Пентаклей показывает женщину в саду с соколом: это самостоятельность, достаток, вкус, контроль над ресурсом и наслаждение плодами труда. Карта говорит о зрелой материальной независимости и умении жить красиво без суеты. Новичку важно смотреть на прирученную птицу: инстинкты и желания уже дисциплинированы, поэтому роскошь не разрушает.`,love:`В отношениях это самостоятельность, высокие стандарты, удовольствие от себя, зрелая независимость.`,work:`В работе это доход, экспертность, статус, личный результат, комфорт, премиальный уровень.`,advice:`Цени свой сад и не обесценивай путь, который сделал тебя самостоятельным.`,rev:`зависимость от комфорта, одиночество за фасадом успеха, траты ради статуса, неуверенность в ценности.`}],
['pentacles-10-ten',{long:`Десятка Пентаклей показывает семью, старшего человека, дом, собак и гербы. Это карта наследия, рода, имущества, долгосрочной устойчивости, семейной системы и результата, который переживает одного человека. В отличие от Девятки, здесь ресурс не личный, а системный. Новичку стоит смотреть на связи между поколениями: что передается, кто включен, кто платит цену за стабильность.`,love:`В отношениях это семья, брак, общие активы, род, дом, долгосрочная надежность.`,work:`В работе это крупная структура, бизнес, недвижимость, наследие, стабильная компания, капитализация.`,advice:`Думай не только о сегодняшней выгоде, но и о системе, которую оставишь после себя.`,rev:`семейные конфликты, проблемы с наследством, нестабильность дома, система давит личность.`}],
['pentacles-11-page',{long:`Паж Пентаклей держит монету и внимательно ее изучает. Это ученик практического мира: обучение, навык, стажировка, финансовая грамотность, первая работа, конкретный план. Карта медленная, но надежная: она говорит о готовности освоить материал руками. Новичку важно читать ее как маленький, но реальный шаг к мастерству.`,love:`В отношениях это надежный, но робкий шаг, забота делом, изучение партнера, практическая симпатия.`,work:`В работе это учеба, стажировка, новая профессия, финансовый план, первая задача, аккуратность.`,advice:`Учись на конкретике: один маленький навык сейчас важнее большой мечты без практики.`,rev:`лень учиться, невнимательность, незрелое отношение к деньгам, шанс не взят в работу.`}],
['pentacles-12-knight',{long:`Рыцарь Пентаклей сидит на спокойном коне и держит монету. Это самый медленный рыцарь, но его сила в надежности, терпении, методичности и готовности делать дело до конца. Карта часто показывает стабильный прогресс, рутину, обязательства и практический подход. Новичку важно не путать медленность с отсутствием движения: здесь движение есть, просто оно земное и последовательное.`,love:`В отношениях это надежность, верность, медленное сближение, забота поступками, предсказуемость.`,work:`В работе это регулярный труд, производственный процесс, ответственность, долгий проект, выполнение обещаний.`,advice:`Иди медленно, но каждый день: устойчивость сейчас ценнее эффекта.`,rev:`застой, упрямство, скука, прокрастинация, чрезмерная осторожность или рутина без смысла.`}],
['pentacles-13-queen',{long:`Королева Пентаклей сидит среди природы с монетой на коленях. Это зрелая земная забота: дом, тело, деньги, уют, практическая поддержка, способность создавать безопасную среду. Она теплая, но очень конкретная: ее любовь выражается делами, ресурсом и качеством быта. Новичку важно видеть связь с природой: изобилие здесь выращено, а не просто получено.`,love:`В отношениях это забота делами, надежность, уют, телесность, готовность вкладываться в быт.`,work:`В работе это управление ресурсами, финансы, HR-забота, качество сервиса, устойчивый доход.`,advice:`Создай среду, где живому будет удобно расти, включая себя.`,rev:`гиперопека, бытовой контроль, усталость от заботы, тревога о деньгах, забывание себя.`}],
['pentacles-14-king',{long:`Король Пентаклей сидит на троне среди символов богатства и плодородия. Это зрелая материальная власть: бизнес, имущество, надежность, результат, управление ресурсами и умение превращать труд в устойчивую систему. Он не обещает мгновенную удачу, он строит фундамент. Новичку стоит читать его как вопрос зрелого владения: кто отвечает за ресурсы и насколько эти ресурсы служат жизни.`,love:`В отношениях это надежный партнер, материальная опора, серьезные намерения, иногда собственничество.`,work:`В работе это владелец бизнеса, руководитель, инвестиции, недвижимость, стабильный доход, зрелое управление.`,advice:`Думай как хозяин ресурса: укрепляй фундамент и отвечай за последствия решений.`,rev:`жадность, жесткий материализм, страх потерь, контроль деньгами или неустойчивый статус.`}]
]);
window.TAROT_MAJOR_MEANINGS = Object.fromEntries(Object.entries(window.TAROT_CARD_MEANINGS).filter(([id]) => id.startsWith('major-')));
window.applyTarotMeanings = function(cards){
  if(!Array.isArray(cards)) return cards;
  cards.forEach(c => {
    const m = window.TAROT_CARD_MEANINGS[c.id];
    if(m){
      if(m.long) c.long = m.long;
      if(m.love) c.love = m.love;
      if(m.work) c.work = m.work;
      if(m.advice) c.advice = m.advice;
      if(m.rev) c.rev = m.rev;
    }
  });
  return cards;
};
document.addEventListener('toggle', function(e){
  const el = e.target;
  if(el && el.matches && el.matches('details.extended') && typeof window.rememberExtended === 'function'){
    window.rememberExtended(el);
  }
}, true);
